svg.script:

var elem;
var svgdoc;
function init(evt) {
   svgdoc = evt.target.ownerDocument;
   elem = svgdoc.getElementById('plane');
   elem.addEventListener("mousemove", mouse_pos, false);
}

function mouse_pos(evt) {
  var crc = svgdoc.getElementById("toShow");
  var posX = evt.clientX;
  var posY = evt.clientY;
  posX = posX;
  posY = posY;
  crc.setAttribute("transform", "translate("+posX+","+posY+")");
}
